import React, { useState, useEffect, useRef } from 'react';
import { slotAPI } from '../services/api';
import io from 'socket.io-client';

const SlotBookingPage = () => {
  const [slots, setSlots] = useState([]);
  const [bookedSlots, setBookedSlots] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [view, setView] = useState('available');
  const [successMessage, setSuccessMessage] = useState('');
  const socketRef = useRef(null);

  useEffect(() => {
    fetchSlots();
  }, []);

  useEffect(() => {
    socketRef.current = io('http://localhost:5000', {
      auth: {
        token: sessionStorage.getItem('token') || localStorage.getItem('token'),
      },
    });

    socketRef.current.on('slot_updated', () => {
      fetchSlots();
    });

    return () => {
      socketRef.current.off('slot_updated');
      socketRef.current.disconnect();
    };
  }, []);

  const fetchSlots = async () => {
    setLoading(true);
    setError('');
    try {
      const [availableRes, bookedRes] = await Promise.all([
        slotAPI.getAvailableSlots(),
        slotAPI.getMySlots(),
      ]);
      setSlots(availableRes.data.slots || []);
      setBookedSlots(bookedRes.data.slots || []);
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to fetch slots');
    } finally {
      setLoading(false);
    }
  };

  const handleBookSlot = async (slotId) => {
    try {
      await slotAPI.bookSlot({ slotId });
      setSuccessMessage('Session booked successfully.');
      setTimeout(() => setSuccessMessage(''), 3000);
      fetchSlots();
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to book slot');
    }
  };

  const handleCancelBooking = async (slotId) => {
    try {
      await slotAPI.cancelBooking(slotId);
      setSuccessMessage('Booking cancelled successfully.');
      setTimeout(() => setSuccessMessage(''), 3000);
      fetchSlots();
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to cancel booking');
    }
  };

  const formatDateTime = (date, time) => {
    try {
      return `${new Date(date).toLocaleDateString()} at ${time}`;
    } catch {
      return `${date} at ${time}`;
    }
  };

  const isSlotFinished = (dateStr, timeStr, durationMinutes) => {
    if (!dateStr || !timeStr) return false;
    try {
      const slotStart = new Date(`${dateStr.split('T')[0]}T${timeStr}`);
      if (isNaN(slotStart.getTime())) return false;

      const slotEnd = new Date(slotStart.getTime() + (durationMinutes || 30) * 60000);
      return new Date() > slotEnd;
    } catch {
      return false;
    }
  };

  const currentSlots = view === 'available' ? slots : bookedSlots;

  return (
    <div className="container-fluid py-5 min-vh-100">
      <div className="container" style={{ maxWidth: '1000px' }}>

        <div className="minimal-page-header d-flex flex-column flex-md-row justify-content-between align-items-md-end gap-3">
          <div>
            <h1 className="minimal-title">Slot Booking</h1>
            <p className="minimal-subtitle mb-0">
              Reserve sessions and manage your scheduled bookings seamlessly.
            </p>
          </div>
          <div className="d-flex gap-2">
            <span className="minimal-badge minimal-badge-success">
              <span className="minimal-badge-dot"></span> {slots.length} Open
            </span>
            <span className="minimal-badge minimal-badge-primary">
              <span className="minimal-badge-dot"></span> {bookedSlots.length} Booked
            </span>
          </div>
        </div>

        {error && (
          <div className="alert alert-danger alert-dismissible fade show border-0 rounded-3" role="alert">
            {error}
            <button type="button" className="btn-close" onClick={() => setError('')}></button>
          </div>
        )}

        {successMessage && (
          <div className="alert alert-success alert-dismissible fade show border-0 rounded-3" role="alert">
            {successMessage}
            <button type="button" className="btn-close" onClick={() => setSuccessMessage('')}></button>
          </div>
        )}

        <div className="minimal-tabs">
          <button
            type="button"
            className={`minimal-tab-btn ${view === 'available' ? 'active' : ''}`}
            onClick={() => setView('available')}
          >
            Available Slots
          </button>
          <button
            type="button"
            className={`minimal-tab-btn ${view === 'booked' ? 'active' : ''}`}
            onClick={() => setView('booked')}
          >
            My Bookings
          </button>
        </div>

        {loading ? (
          <div className="text-center py-5">
            <div className="spinner-border text-primary" role="status">
              <span className="visually-hidden">Loading...</span>
            </div>
          </div>
        ) : currentSlots.length === 0 ? (
          <div className="text-center py-5">
            <div className="mb-3 text-muted opacity-50">
              <svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
                <rect x="3" y="4" width="18" height="18" rx="2" ry="2"></rect><line x1="16" y1="2" x2="16" y2="6"></line><line x1="8" y1="2" x2="8" y2="6"></line><line x1="3" y1="10" x2="21" y2="10"></line>
              </svg>
            </div>
            <h5 className="fw-bold mb-2">No sessions found</h5>
            <p className="text-muted">
              {view === 'available'
                ? 'Check back later as staff update their schedules.'
                : "You don't have any upcoming bookings right now."}
            </p>
          </div>
        ) : (
          <div className="minimal-list-group">
            {currentSlots.map((slot) => (
              <div key={slot._id} className="minimal-list-item gap-3 gap-md-4">
                <div className="minimal-avatar flex-shrink-0">
                  {slot.staffId?.name ? slot.staffId.name.charAt(0).toUpperCase() : 'S'}
                </div>

                <div className="flex-grow-1" style={{ minWidth: 0 }}>
                  <div className="d-flex flex-column flex-md-row align-items-md-center gap-1 gap-md-3 mb-1">
                    <h6 className="fw-bold mb-0 text-truncate">{slot.staffId?.name || 'Staff Member'}</h6>
                    <span className="minimal-meta-text text-truncate">{slot.staffId?.subject || 'Subject'}</span>
                  </div>
                  <div className="minimal-meta-text">
                    {formatDateTime(slot.date, slot.time)} • {slot.duration}m
                    {slot.topic && ` • ${slot.topic}`}
                  </div>
                </div>

                <div className="d-flex align-items-center gap-3 ms-md-auto w-100 w-md-auto mt-2 mt-md-0 justify-content-end">
                  {isSlotFinished(slot.date, slot.time, slot.duration) ? (
                    <button className="btn btn-sm btn-light border" disabled>
                      Finished
                    </button>
                  ) : view === 'available' ? (
                    <button className="btn btn-sm btn-outline-primary px-4 rounded-pill" onClick={() => handleBookSlot(slot._id)}>
                      Book
                    </button>
                  ) : (
                    <button className="btn btn-sm btn-outline-danger px-4 rounded-pill" onClick={() => handleCancelBooking(slot._id)}>
                      Cancel
                    </button>
                  )}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default SlotBookingPage;
